import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../utils/AuthContext';
import API from '../utils/api';

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const res = await API.post('/auth/login', form);
      login(res.data.user, res.data.token);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Login failed. Please try again.');
    }
    setLoading(false);
  };

  return (
    <div className="auth-page">
      {/* Left panel */}
      <div className="auth-left">
        <div style={{ position:'relative', zIndex:1, maxWidth: 480 }}>
          <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:48 }}>
            <div style={{ width:44, height:44, background:'linear-gradient(135deg,#6366f1,#8b5cf6)', borderRadius:12, display:'flex', alignItems:'center', justifyContent:'center', fontSize:20 }}>🎯</div>
            <span style={{ fontFamily:'Syne,sans-serif', fontSize:24, fontWeight:800, background:'linear-gradient(135deg,#fff,#818cf8)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' }}>PlaceAI</span>
          </div>

          <h1 style={{ fontFamily:'Syne,sans-serif', fontSize:42, fontWeight:800, lineHeight:1.1, marginBottom:20, letterSpacing:'-1px' }}>
            Land your<br />
            <span style={{ background:'linear-gradient(135deg,#6366f1,#22d3ee)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' }}>dream job</span><br />
            with AI
          </h1>

          <p style={{ color:'var(--text2)', fontSize:16, lineHeight:1.7, marginBottom:40, maxWidth:360 }}>
            Personalized placement preparation powered by AI. Practice interviews, track progress, match with companies.
          </p>

          <div style={{ display:'flex', flexDirection:'column', gap:14 }}>
            {[
              ['🤖', 'AI Mock Interviews', 'Practice with real-time feedback'],
              ['📊', 'Company Matching', 'See which companies you qualify for'],
              ['🎯', 'Smart Roadmap', '30-day personalized study plan'],
            ].map(([icon, title, desc]) => (
              <div key={title} style={{ display:'flex', alignItems:'center', gap:14 }}>
                <div style={{ width:40, height:40, background:'rgba(99,102,241,0.12)', border:'1px solid rgba(99,102,241,0.2)', borderRadius:10, display:'flex', alignItems:'center', justifyContent:'center', fontSize:18, flexShrink:0 }}>{icon}</div>
                <div>
                  <div style={{ fontSize:14, fontWeight:600 }}>{title}</div>
                  <div style={{ fontSize:12, color:'var(--text3)', marginTop:1 }}>{desc}</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Right panel */}
      <div className="auth-right">
        <div className="auth-form">
          <div style={{ marginBottom:32 }}>
            <h2 className="auth-title">Welcome back</h2>
            <p className="auth-subtitle">Sign in to continue your preparation</p>
          </div>

          {error && <div className="alert alert-error" style={{ marginBottom:20 }}>⚠️ {error}</div>}

          <form onSubmit={handleSubmit}>
            <div className="form-group" style={{ marginBottom:16 }}>
              <label className="form-label">Email Address</label>
              <input
                className="form-input"
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={e => setForm({...form, email: e.target.value})}
                required
              />
            </div>

            <div className="form-group" style={{ marginBottom:24 }}>
              <label className="form-label">Password</label>
              <input
                className="form-input"
                type="password"
                placeholder="••••••••"
                value={form.password}
                onChange={e => setForm({...form, password: e.target.value})}
                required
              />
            </div>

            <button className="btn btn-primary btn-lg" type="submit" disabled={loading} style={{ width:'100%', marginBottom:20 }}>
              {loading ? <><div className="spinner" style={{width:16,height:16,borderWidth:2}} /> Signing in...</> : 'Sign In →'}
            </button>
          </form>

          <p style={{ textAlign:'center', fontSize:13.5, color:'var(--text2)' }}>
            Don't have an account?{' '}
            <Link to="/register" style={{ color:'var(--indigo2)', fontWeight:600, textDecoration:'none' }}>
              Create one free
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
}
